package com.trivaris.votechain

import com.trivaris.votechain.blockchain.BlockDatabaseManager
import com.trivaris.votechain.blockchain.database.BlockObject
import com.trivaris.votechain.blockchain.SerializableKeyPair
import com.trivaris.votechain.networking.Message
import com.trivaris.votechain.networking.MessageEnvelope
import com.trivaris.votechain.networking.MessageManager
import com.trivaris.votechain.networking.messagehandlers.MessageType
import com.trivaris.votechain.voting.VotingManager
import kotlinx.serialization.Serializable
import kotlinx.serialization.json.Json
import java.io.File
import java.security.KeyPair
import javax.imageio.ImageIO
import kotlin.collections.Map

object Server {
    private val json = Json {
        prettyPrint = true
        encodeDefaults = true
    }
    private val participants: MutableSet<String> = mutableSetOf()

    private val keypairs: List<KeyPair> =
        if (Config.data.debugMode) debugKeypairs
        else List(Config.data.keypairAmount) { Cryptography.generateKeyPair() }

    private val decryptionMap: Map<String, String> = keypairs.associate {
        val publicKeyString = it.public.asString()
        val publicKeyHash = publicKeyString.applySha256()
        publicKeyHash to publicKeyString
    }

    fun keysResponse(originator: String) {
        val message = Message(MessageType.KEYS_RESPONSE, json.encodeToString(decryptionMap))
        val envelope = MessageEnvelope(message, originator)
        MessageManager.outgoing(envelope)
    }

    private fun saveKeys() {
        File("keys/").apply { mkdir() }
        keypairs.forEachIndexed { index, keypair ->
            val serialized = SerializableKeyPair(keypair)
            val jsonKeypair = json.encodeToString(serialized)
            val qr = jsonKeypair.toQRCode()
            val file = File("keys/keypair-${index}.png").apply { createNewFile() }

            ImageIO.write(qr, "PNG", file)
        }
    }

    fun joinResponse(requester: String) {
        participants.forEach {
            val newParticipantMessage = Message(MessageType.NEW_PARTICIPANT, requester)
            val newParticipantEnvelope = MessageEnvelope(newParticipantMessage, it)
            MessageManager.outgoing(newParticipantEnvelope)
        }

        participants.add(requester)
        Logger.log(Logger.SERVER, Logger.DEBUG, message = "New participants: $participants")

        val data = JoinData()
        Logger.SERVER.log("Sending info:", "Participants: ${data.participants}", "Blocks: ${data.blocks.size}", "Current Votes: ${data.currentVotes.size}", showOnAndroid = false)
        val message = Message(MessageType.JOIN_RESPONSE, json.encodeToString(data))
        val envelope = MessageEnvelope(message, requester)

        MessageManager.outgoing(envelope)
    }

    @Serializable
    data class JoinData(
        val participants: MutableSet<String> = Server.participants,
        val currentVotes: MutableMap<String, String> = VotingManager.getCurrentVotes(),
        val blocks: List<BlockObject> = BlockDatabaseManager.longestChain()
    )

    init {
        if (Config.data.isServer) {
            Logger.SERVER.log("Creating and saving keys...")
            saveKeys()
        }
    }
}

const val debugKeysString = "[{\"public\":\"\",\"private\":\"\"},{\"public\":\"\",\"private\":\"\"},{\"public\":\"\",\"private\":\"\"},{\"public\":\"\",\"private\":\"\"},{\"public\":\"\",\"private\":\"\"},{\"public\":\"\",\"private\":\"\"},{\"public\":\"\",\"private\":\"\"},{\"public\":\"\",\"private\":\"\"},{\"public\":\"\",\"private\":\"\"},{\"public\":\"\",\"private\":\"\"}]"
val debugKeypairs = Json.decodeFromString<List<SerializableKeyPair>>(debugKeysString).map { it.getKeyPair() }

